CREATE INDEX IF NOT EXISTS ix_tenant_status ON integrarp.tenant(status);
CREATE INDEX IF NOT EXISTS ix_tenant_criado_em ON integrarp.tenant(criado_em);
DROP TRIGGER IF EXISTS trg_tenant_atualizado_em ON integrarp.tenant; CREATE TRIGGER trg_tenant_atualizado_em BEFORE UPDATE ON integrarp.tenant FOR EACH ROW EXECUTE FUNCTION integrarp.set_atualizado_em();
