DO $$ BEGIN IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname='uq_tenant_slug') THEN ALTER TABLE integrarp.tenant ADD CONSTRAINT uq_tenant_slug UNIQUE (codigo); END IF; END $$;
CREATE INDEX IF NOT EXISTS ix_tarefa_prioridade ON integrarp.tarefa(prioridade);
CREATE INDEX IF NOT EXISTS ix_tarefa_responsavel ON integrarp.tarefa(responsavel_usuario_id);
CREATE INDEX IF NOT EXISTS ix_tarefa_busca ON integrarp.tarefa USING gin(to_tsvector('portuguese', coalesce(nome,'')));
CREATE OR REPLACE VIEW integrarp.vw_dashboard_operacional AS SELECT 0::int AS tarefas_abertas, 0::int AS processos_em_atraso, 0::int AS estoque_critico;
CREATE OR REPLACE VIEW integrarp.vw_tarefas_abertas AS SELECT * FROM integrarp.tarefa WHERE excluido_em IS NULL AND status <> 'concluida';
CREATE OR REPLACE VIEW integrarp.vw_processos_em_atraso AS SELECT * FROM integrarp.processo_instancia WHERE excluido_em IS NULL AND status = 'atrasado';
CREATE OR REPLACE VIEW integrarp.vw_estoque_critico AS SELECT * FROM integrarp.produto WHERE excluido_em IS NULL AND (dados->>'estoque_critico') = 'true';
CREATE OR REPLACE VIEW integrarp.vw_projeto_central_resumo AS SELECT b.id, b.nome, count(i.id) AS total_itens FROM integrarp.projeto_central_board b LEFT JOIN integrarp.projeto_central_item i ON i.tenant_id=b.tenant_id GROUP BY b.id,b.nome;
